configuration.jsScript:
var type = msg.params.type;
var serverObject = {
    entityName_Gateway : metadata.originatorName
}
var sharedObject = {}
var telemetriObject = {}
msg = {};
msg.serverObject = serverObject;
msg.sharedObject = sharedObject;
msg.telemetriObject = telemetriObject;
msgType = "POST_ATTRIBUTES_REQUEST";
return {
    msg: msg,
    metadata: metadata,
    msgType: msgType
};

